#include<iostream>#include<vector>#include<algorithm>#include<unordered_map>#include<climits>#define ll long longusing namespace std;int main(){    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> a(n);                for(int i=0;i<n;i++){            cin>>a[i];                    }                sort(a.begin(),a.end());        reverse(a.begin(),a.end());        int cnt=0;        for(int i=0;i<n;i++){            if(a[0]==a[i]){                cnt++;            }            else{                break;            }        }        cout<<cnt<<"\n";    }}